{
  "title": "Экранирование имен столбцов",
  "group": "Экранирование 2",
  "options": [
    {
      "text": "first.name"
    },
    {
      "text": "\"first.name\""
    },
    {
      "text": "\\"
    },
    {
      "text": "[first.name]"
    },
